  assert_eq!(
    sep_pair_abc_def(&b"xxx,def"[..]),
    Err(Err::Error(error_position!(&b"xxx,def"[..], ErrorKind::Tag)))
  );
  assert_eq!(
    sep_pair_abc_def(&b"abc,xxx"[..]),
    Err(Err::Error(error_position!(&b"xxx"[..], ErrorKind::Tag)))
  );
}

fn sep_pair_abc_def(i: &[u8]) -> IResult<&[u8], (&[u8], &[u8])> {
