fn preceded_test() {
  fn preceded_abcd_efgh(i: &[u8]) -> IResult<&[u8], &[u8]> {
    preceded(tag("abcd"), tag("efgh")).parse(i)
  }

  assert_eq!(
    preceded_abcd_efgh(&b"abcdefghijkl"[..]),
    Ok((&b"ijkl"[..], &b"efgh"[..]))
